class Bok:

  def __init__(self, titel, av, sidor, lånad):
    self.titel = titel
    self.författare = av
    self.antal_sidor = sidor
    self.lånad = lånad

  def __str__(self):
    return self.titel +  ", skriven av: " + self.författare + ", har " + str(self.antal_sidor) + " sidor."

  def lägg_till_förord(self, nya_sidor):
    self.antal_sidor += nya_sidor

  def låna(self):
    self.lånad = True

  def lämna_in(self):
    self.lånad = False

from bok import *

class Ljudbok(Bok):
  pass
